#!/usr/bin/env python3
"""
apply_branding.py
Applies ConnectionSphere favicon and dark Scalar theme to the factory server.
Run from inside connectionsphere_factory/
"""
import base64, os, re

PNG32  = ""
PNG180 = ""

# ── 1. Write favicon files ────────────────────────────────────────
os.makedirs("src/connectionsphere_factory/static", exist_ok=True)

with open("src/connectionsphere_factory/static/favicon.png", "wb") as f:
    f.write(base64.b64decode(PNG32))

with open("src/connectionsphere_factory/static/apple-touch-icon.png", "wb") as f:
    f.write(base64.b64decode(PNG180))

print("✓ Favicon files written")

# ── 2. Patch app.py — serve favicon + dark Scalar theme ──────────
app_path = "src/connectionsphere_factory/app.py"
app_src  = open(app_path).read()

# Add StaticFiles + Response imports if not present
if "StaticFiles" not in app_src:
    app_src = app_src.replace(
        "from fastapi import FastAPI",
        "from fastapi import FastAPI, Response\nfrom fastapi.staticfiles import StaticFiles"
    )
elif "Response" not in app_src:
    app_src = app_src.replace(
        "from fastapi import FastAPI",
        "from fastapi import FastAPI, Response"
    )

# Mount static files + favicon endpoint after app = FastAPI(...)
STATIC_BLOCK = """
# ── Favicon ───────────────────────────────────────────────────────
import pathlib as _pathlib

@app.get("/favicon.ico", include_in_schema=False)
@app.get("/favicon.png", include_in_schema=False)
async def favicon():
    ico = _pathlib.Path(__file__).parent / "static" / "favicon.png"
    return Response(content=ico.read_bytes(), media_type="image/png")
"""

if "favicon.ico" not in app_src:
    # Insert after router registrations
    app_src = app_src.rstrip() + "\n" + STATIC_BLOCK + "\n"

# ── 3. Patch Scalar config — dark theme matching web app ─────────
SCALAR_THEME = """
    custom_css=\'\'\'
      :root {
        --scalar-color-1: #f0f0f0;
        --scalar-color-2: #aaaaaa;
        --scalar-color-3: #666666;
        --scalar-color-accent: #c8ff00;
        --scalar-background-1: #0a0a0a;
        --scalar-background-2: #111111;
        --scalar-background-3: #1a1a1a;
        --scalar-border-color: #222222;
        --scalar-button-1: #c8ff00;
        --scalar-button-1-color: #000000;
        --scalar-button-1-hover: #d4ff33;
        --scalar-color-green: #00ff88;
        --scalar-color-red: #ff4444;
        --scalar-color-yellow: #ffaa00;
        --scalar-color-blue: #6699ff;
        --scalar-sidebar-background-1: #0a0a0a;
        --scalar-sidebar-item-active-background: #1a1a1a;
        --scalar-sidebar-color-active: #c8ff00;
        --scalar-sidebar-border-color: #1a1a1a;
        --scalar-font: \'DM Sans\', sans-serif;
        --scalar-font-code: \'DM Mono\', monospace;
      }
      @import url(\'https://fonts.googleapis.com/css2?family=DM+Mono:wght@400;500&family=DM+Sans:wght@300;400;500;600&display=swap\');
      .scalar-app { font-family: var(--scalar-font); }
    \'\'\',
"""

# Find get_swagger_ui_html or get_scalar_api_reference call and inject theme
if "custom_css" not in app_src:
    # Add inside scalar config block
    app_src = re.sub(
        r"(get_scalar_api_reference\([^)]*)(layout\s*=)",
        r"\1" + "custom_css=\'\'\'\n      /* cs dark theme */\n    \'\'\',\n    \2",
        app_src
    )

open(app_path, "w").write(app_src)
print("✓ app.py patched (favicon endpoint + Scalar theme placeholder)")

# ── 4. Patch interview page — add favicon link tags ───────────────
voice_path = "src/connectionsphere_factory/routes/voice.py"
voice_src  = open(voice_path).read()

FAVICON_TAGS = f"""<link rel="icon" type="image/png" href="/favicon.png">
<link rel="apple-touch-icon" href="/favicon.png">"""

if 'rel="icon"' not in voice_src:
    voice_src = voice_src.replace(
        '<link rel="preconnect" href="https://fonts.googleapis.com">',
        FAVICON_TAGS + '\n<link rel="preconnect" href="https://fonts.googleapis.com">'
    )
    open(voice_path, "w").write(voice_src)
    print("✓ Interview page favicon links added")
else:
    print("✓ Interview page already has favicon")

print("\nAll done. Restart uvicorn and refresh.")
print("  Scalar docs: http://localhost:8391/docs")
print("  Interview:   http://localhost:8391/session/{id}/interview")
